import json, os

def merge_comm(path, updates):
    data = json.load(open(path)) if os.path.exists(path) else {}
    for ch, verses in updates.items():
        if ch not in data:
            data[ch] = {}
        for v, html in verses.items():
            if v not in data[ch]:
                data[ch][v] = html
    json.dump(data, open(path, 'w'), ensure_ascii=False, indent=2)
    print(f"wrote {path}")

BOOK = "2samuel"
PATH = f"data/commentary/mkt-original/{BOOK}.json"

# 2 Samuel 14–16: Joab's Tekoa scheme, Absalom's return/portrait, Shimei's cursing,
# and David's flight through Benjamin. mkt-original linguistic commentary.

CH14 = {
    # v14 already present
    "1": "<p><em>Vayeda Yoav ben-Tzeruyah ki lev ha-melekh al-Avshalom</em> — &ldquo;And Joab son of Zeruiah knew that the heart of the king was toward Absalom.&rdquo; The verb <em>yada</em> (know) here is political perception — Joab reads David's emotional state as intelligence requiring action. <em>Lev...al</em> (heart toward) is an idiom of longing or inclination found in Ruth 2:21; it describes not mere preference but active desire that Joab recognizes as leverage. The Zeruiah patronym marks Joab as part of the Zeruiah family military complex — cousin-executors who carry out what David cannot or will not do directly.</p>",
    "2": "<p><em>Vayishlach Yoav Teqo'ah</em> — &ldquo;And Joab sent to Tekoa.&rdquo; Tekoa (<em>teqoa'</em>) is a village about 10 km south of Bethlehem, on the edge of the Judean wilderness. The designation <em>ishah chakhamah</em> (wise woman) marks professional skill in rhetoric and strategy (cf. 20:16, the wise woman of Abel). The instruction to mourn (<em>hitabbeli na</em>) — put on mourning garments (<em>begdei-avel</em>) and not anoint with oil — is a scripting of outward appearance to match a legal presentation.</p>",
    "3": "<p><em>Vayasem Yoav be-phiha et-ha-devarim</em> — &ldquo;And Joab put the words in her mouth.&rdquo; The phrase <em>sim be-pheh</em> (put in the mouth) is technical terminology for scripted speech — it appears in Exod 4:15 (God putting words in Moses' mouth) and the prophetic call narratives. Joab's use of the formula places him as a kind of human author of the woman's oracle — giving her words the performative weight of a commissioned speech.</p>",
    "4": "<p><em>Vattomer ha-ishah ha-Teqo'it el-ha-melekh vattippol al-paneyha</em> — the prostration formula (<em>naphel al-panim</em>) before the king combined with <em>hoshi'ah ha-melekh</em> (save, O king) deploys the recognized petition vocabulary of ancient Israelite royal justice. The combination of posture and cry activates the king's judicial obligation; a king who fails to respond to a prostrate petitioner's <em>hoshi'ah</em> cry violates his covenant role as guarantor of justice.</p>",
    "5": "<p><em>Ishah almanah ani</em> — &ldquo;I am a widow woman.&rdquo; The self-identification as widow positions the speaker within the legally protected class of those without male representation. <em>Almanah</em> (widow) designates the woman in the liminal legal state between marriage and remarriage — without a husband's protection but not yet freed from the household. The widow's triple vulnerability — no husband, potentially no sons, economically precarious — is the exact legal category that Deuteronomic legislation required kings to protect.</p>",
    "6": "<p><em>Vattikker ishah ha-eved shney vanim</em> — &ldquo;And your servant had two sons.&rdquo; <em>Yinnatzu ba-sadeh</em> (they quarreled in the field) uses the Niphal of <em>natzah</em>, a verb for serious fighting — the same root appears in Exod 2:13. The field setting (<em>ba-sadeh</em>) echoes the Cain-Abel narrative (Gen 4:8 — &ldquo;when they were in the field&rdquo;), reinforcing the fratricide typology that the Tekoa parable deliberately invokes.</p>",
    "7": "<p><em>Vehinneh qamah khol ha-mishpachah al-amatekhah</em> — &ldquo;And behold, the whole clan rose against your maidservant.&rdquo; <em>Mishpachah</em> (clan) is the intermediate social unit between household and tribe; the clan's role in blood vengeance (<em>go'el ha-dam</em>) was both legal right and social obligation. The demand — <em>naphesh b'nephesh</em> (soul for soul) — invokes the lex talionis formula of Lev 24:17–21. The counter-phrase <em>ve-khilatnu gam et-ha-yoresh</em> (we will destroy the heir also) — <em>kalah</em> (destroy utterly) — signals total annihilation of the family line.</p>",
    "8": "<p><em>Vayomer ha-melekh el-ha-ishah: lekhi le-veitekhah</em> — David's initial response uses the judicial deferral formula. <em>Atsaveh alayikh</em> (I will give orders concerning you) is an administrative holding action — the king acknowledges the case without yet pronouncing judgment. This deferral opens the space the woman needs to press for a stronger commitment.</p>",
    "9": "<p><em>Vattomer ha-ishah ha-Teqo'it el-ha-melekh: alai adoni ha-melekh ha-avon</em> — &ldquo;Let the guilt be on me, my lord the king.&rdquo; The liability-transfer formula — <em>alai ha-avon</em> (upon me the iniquity) — appears in Gen 27:13 (Rebekah to Jacob) as a formal assumption of legal responsibility. The king and his throne are explicitly released from guilt (<em>nizku</em>) — a legally precise exculpation formula.</p>",
    "10": "<p><em>Vayomer ha-melekh: asher yedabber elekhah — haveil'hu elai</em> — David's escalated commitment — &ldquo;whoever speaks to you, bring him to me, and he shall not touch you again&rdquo; — moves from administrative deferral to active royal protection. <em>Lo yosif od la-negoa' bakh</em> (he shall not touch you again) uses the Hiphil of <em>nagha'</em> with the negative future — a formula of ongoing protection that functions as a royal decree.</p>",
    "11": "<p><em>Vattomer: yizkor na ha-melekh et-YHWH elohav</em> — the woman's escalation to a divine oath is the decisive step. <em>Yizkor</em> (let him invoke) combined with YHWH as guarantor transforms David's royal word into a divine oath. <em>Chai YHWH</em> — the oath formula &ldquo;as YHWH lives&rdquo; — is the strongest possible commitment. <em>Im yippol mi-sso'ar benekh artzah</em> (not one hair of your son shall fall to the ground) echoes the protective oath of 1 Sam 14:45 — making the formula recognizable as a maximum-protection guarantee.</p>",
    "12": "<p><em>Vattomer ha-ishah: tedabber na amatekhah el-adoni ha-melekh davar</em> — the formal request for permission to continue the discourse. Having secured the maximum commitment (divine oath), the woman now pivots from fictional case to royal application. The pivot structure is identical to Nathan's approach in ch. 12: secure agreement on the principle before applying it.</p>",
    "13": "<p><em>Lammah chashavta kakha al-am elohim</em> — &ldquo;Why have you devised like this against the people of God?&rdquo; The charge uses <em>chashav</em> (devise, plan) — the vocabulary of calculated sin rather than inadvertent error. <em>Am elohim</em> (people of God) frames the matter as a covenant-community issue. <em>Ve-min-dibber ha-melekh ha-davar ha-zeh ke-ashemim</em> — the woman argues that David's silence on Absalom generates the same legal category as the fictional crime: guilt requiring remediation.</p>",
    "15": "<p><em>Ve-attah asher-bati ledabber el-ha-melekh ha-davar ha-zeh ki yir'uni ha-am</em> — the woman's stated motive — the people made her afraid — is the face-saving narrative that allows Absalom's return to feel like it responds to a popular concern rather than a royal capitulation. <em>Ve-to'mer amatekhah adabber na el-ha-melekh</em> maintains the deferential register while the content has already made the application explicit.</p>",
    "16": "<p><em>Ve-shama' ha-melekh le-hatzil et-amato mi-yad ha-ish</em> — the phrase <em>le-hatzil</em> (to deliver, rescue) connects the king's judicial function to YHWH's own characteristic action of deliverance. <em>Mi-nachalat elohim</em> — the appeal to &ldquo;the heritage of God&rdquo; makes the land itself the stake: destroying the heir destroys the family's claim to its portion of YHWH's land, violating the cosmic-legal order.</p>",
    "17": "<p><em>Ki yihyeh devar adoni ha-melekh le-menucha</em> — &ldquo;for the word of my lord the king will give rest (<em>menucha</em>).&rdquo; <em>Menucha</em> is the vocabulary of covenant rest and security — it appears in Deut 12:9 and Ruth 3:1. The comparison of the king to an angel (<em>ke-malakh ha-elohim</em>) to discern good and evil (<em>lishmo'a ha-tov ve-ha-ra'</em>) attributes quasi-divine judicial discernment to the king — the same quality Solomon requests (1 Kgs 3:9).</p>",
    "18": "<p><em>Vaya'an ha-melekh vayomer el-ha-ishah: al-na tekhaddi mimmenni davar asher anokhi sho'el otakh</em> — David's direct question — &ldquo;is the hand of Joab with you in all this?&rdquo; — uses <em>yad Yoav</em> (the hand of Joab) as an idiomatic expression for instrumental agency. <em>Yad</em> in this context is the biblical idiom for agency — as in <em>bi-yad Moshe</em> (by the hand of Moses). David's reading of the parable-trap reveals his acute political intelligence.</p>",
    "19": "<p><em>Vatta'an ha-ishah vattomer: chai naphshekha adoni ha-melekh</em> — the woman's admission that Joab &ldquo;put all these words in the mouth&rdquo; (<em>sam et-kol ha-devarim ha-elleh be-phi amatekhah</em>) uses the precise technical term of v. 3. The honesty of the admission — after the device has already succeeded — reflects the protocol of acknowledging agency once the outcome was secured. <em>Ki avdekha Yoav tzivvani</em> (for your servant Joab commanded me) publicly credits Joab.</p>",
    "20": "<p><em>Le-sabbev et-penei ha-davar asah avdekha Yoav et-ha-davar ha-zeh</em> — &ldquo;to change the face of the matter (<em>penei ha-davar</em>) your servant Joab did this.&rdquo; The phrase <em>le-sabbev et-penei ha-davar</em> is unique — literally &ldquo;to turn the face of the matter&rdquo; — idiom for changing the current state of affairs. David's acceptance — comparing Joab to an angel knowing &ldquo;all that is on earth&rdquo; (<em>kol-asher ba-aretz</em>) — uses angelic omniscience as the highest compliment for political wisdom.</p>",
    "21": "<p><em>Va-yiqra ha-melekh el-Yoav vayomer: hinneh-na asiti et-ha-davar ha-zeh</em> — &ldquo;Behold, I have done this thing.&rdquo; <em>Hinneh-na</em> (behold, now) with the first person perfect signals a formal royal grant. <em>Lekh hashev et-ha-na'ar et-Avshalom</em> — &ldquo;go, bring back the young man Absalom.&rdquo; The word <em>na'ar</em> (young man) as the designation for a man probably in his early thirties is David's persistent parental register — the affectionate diminutive that overrides the political classification of rebel.</p>",
    "22": "<p><em>Vayippol Yoav el-panav artzah vayishtachu vayevarekh et-ha-melekh</em> — the full prostration formula (<em>naphol al-panim, hishtachaveh</em>) combined with blessing (<em>berakh</em>) is the complete response to royal grace. <em>Va-yomer Yoav: ha-yom yada avdekha ki-matzati chen be-einekha adoni ha-melekh</em> — &ldquo;this day your servant knows that I have found favor in your eyes.&rdquo; <em>Matza chen be-einei</em> (find favor in the eyes of) is the standard formula for royal approval, appearing from Genesis through Samuel.</p>",
    "23": "<p><em>Vayaqom Yoav vayyelekh Geshura vayabe' et-Avshalom Yerushalaim</em> — the summary of the Geshur retrieval mission. Geshur was the Transjordanian kingdom of Talmai, Absalom's grandfather (3:3); the diplomatic mission required royal negotiation between two courts. <em>Vayavo Yerushalaim</em> (and he came to Jerusalem) closes the exile — physically ending the three-year separation.</p>",
    "24": "<p><em>Vayomer ha-melekh: yissov el-beito u-pheni lo yir'eh</em> — &ldquo;Let him go to his own house, but my face he shall not see.&rdquo; <em>Panai lo yir'eh</em> (my face he shall not see) is the formal language of royal exclusion — the same vocabulary used for the impossibility of seeing YHWH's face in Exod 33:20. Access to the royal <em>panim</em> (face) was the sign of political favor and court membership; exclusion from the royal presence was a form of civil death.</p>",
    "25": "<p><em>Ve-ke-Avshalom lo-hayah ish yapheh be-khol Yisra'el le-hallel me'od</em> — &ldquo;And like Absalom there was no man so handsome in all Israel to be greatly praised.&rdquo; <em>Yapheh me'od</em> (very handsome) deploys the same superlative beauty language used for Joseph (Gen 39:6) and David himself (1 Sam 16:12). The phrase <em>le-hallel me'od</em> (greatly praised) adds the social dimension — beauty was publicly celebrated. The head-to-toe survey (<em>mi-kaph raglo ve-ad qodqod</em>) marks total physical perfection.</p>",
    "26": "<p><em>U-ve-gorzo et-rosho</em> — the Piel participle <em>gozzezo</em> marks the technical shearing action. <em>Va-yishqol et-se'ar rosho matayim sheqel be-even ha-melekh</em> — &ldquo;and he weighed the hair of his head at two hundred shekels by the king's weight.&rdquo; The <em>even ha-melekh</em> (king's stone/weight) was the royal standard of measurement — cf. 12:30. Two hundred shekels by this standard was approximately 2.3 kg — physiologically impossible for one year's growth, signaling hyperbolic praise of extraordinary physical nature. The same hair will become the instrument of his death (18:9).</p>",
    "27": "<p><em>Vayivvaledu le-Avshalom shloshah vanim</em> — Absalom's three sons are not named, but his daughter is: <em>Tamar</em> — the same name as his violated sister (13:1). <em>Veshemah Tamar ve-hi hayetah ishah yephath mar'eh</em> — &ldquo;and her name was Tamar and she was a woman of beautiful appearance.&rdquo; The naming of his daughter after his sister is an act of memorial honor. The beauty vocabulary <em>yephath mar'eh</em> echoes Tamar (13:1) and Absalom (v. 25) — the family's tragic aesthetic lineage: magnificent appearance bound to violent fate.</p>",
    "28": "<p><em>Vayeshev Avshalom Yerushalaim shnatayim yamim u-phene ha-melekh lo ra'ah</em> — <em>shnatayim yamim</em> (two years of days) is an emphatic duration. <em>Penei ha-melekh lo ra'ah</em> (the face of the king he did not see) repeats the exclusion formula of v. 24. The excluded prince in Jerusalem without access to the king is a politically untenable position — better exile than this unresolved half-status that cannot produce legitimate political capacity.</p>",
    "29": "<p><em>Va-yishlach Avshalom el-Yoav lishlo'ach oto el-ha-melekh ve-lo avah la-vo elav</em> — Absalom's twice-attempted summoning of Joab and Joab's twice-refusal (<em>ve-lo avah la-vo</em>). The Piel of <em>avah</em> with negative (<em>lo avah</em>) signals deliberate refusal, not inability — Joab chose not to come. Having achieved Absalom's return, Joab has no incentive to maintain association with the still-excluded prince.</p>",
    "30": "<p><em>Va-yomer el-avadav: re'u chelqat Yoav el-yadi u-vah se'orim</em> — Absalom's instruction to burn Joab's barley field. <em>Chelqah</em> (plot, portion of land) uses the same word as inheritance portions. <em>Vatishtsu avdei Avshalom et-ha-chelqah ba-esh</em> — the servants burning the field is a calculated crime designed to force legal resolution. Deliberate crop-burning (<em>seraph ba-esh</em>) created an unavoidable legal claim that compelled Joab to acknowledge Absalom's existence.</p>",
    "31": "<p><em>Va-yaqom Yoav vayavo el-Avshalom ha-baitah</em> — Joab's forced appearance at Absalom's house fulfills the provocation's goal. <em>Lammah sadekha hirpu avadekhah ba-esh</em> — Joab's outraged question about the burned field uses <em>hirpu</em> (Piel of <em>rapa'</em>) meaning to act recklessly. The question is legally framed — Joab is making a formal complaint that requires Absalom to justify the action.</p>",
    "32": "<p><em>Va-yomer Avshalom el-Yoav: hinneh shalachti elekhah lemor: bo hinnah ve-eshlachakha el-ha-melekh lemor: lammah bati mi-Geshur</em> — Absalom's speech is a formal legal demand for adjudication. <em>Lammah bati mi-Geshur</em> (why have I come from Geshur?) frames his situation as unresolved. <em>Tov li hayah sham</em> (it would have been better for me there) — the comparative idiom of preferred prior state signals the legal argument: partial return without adjudication is worse than exile. <em>Ve-attah er'eh penei ha-melekh ve-im-yesh bi avon ve-hemitani</em> — the binary demand: restoration or execution, refusing the ambiguous middle ground.</p>",
    "33": "<p><em>Va-yavo Yoav el-ha-melekh vayagged-lo</em> — Joab's report activates the final sequence. <em>Vayiqra el-Avshalom</em> (and he summoned Absalom). <em>Vayavo el-ha-melekh va-yishtachu lo al-appav artzah</em> — Absalom's prostration (<em>hishtachaveh al-appayim artzah</em>) — the fullest submission posture. <em>Vayishaq ha-melekh le-Avshalom</em> — David's kiss is the formal restoration of relational status. The narrative ends without any reckoning for Amnon's murder, without any justice for Tamar. The political reconciliation is hollow at its center — the unaddressed guilt that will fuel the revolt of chs. 15–19.</p>",
}

CH15 = {
    # v26 and v30 already present
    "1": "<p><em>Vayehe acharei-chen va-ya'as lo Avshalom merkavah ve-susim ve-chamishim ish ratzim lefanav</em> — Absalom's preparations: <em>merkavah</em> (chariot), <em>susim</em> (horses), and <em>chamishim ish ratzim lefanav</em> (fifty men running before him). The <em>ratzim</em> (running men) is precisely the royal guard unit Samuel warned about in 1 Sam 8:11 — <em>ve-sam lo ratzim lifanav</em>. The deliberate echo marks Absalom's display as the fulfillment of Samuel's anti-kingship oracle. <em>Merkavah ve-susim</em> are the symbols of Egyptian and Canaanite royal military power; Absalom performs the monarchy of the surrounding nations, not the Deuteronomic ideal.</p>",
    "2": "<p><em>Ve-hishkim Avshalom ve-amad al-yad derekh ha-sha'ar</em> — Absalom's early rising to stand beside the gate road. <em>Hishkim</em> (rise early) signals deliberate and sustained effort — this is a daily practice. The city gate (<em>sha'ar</em>) was the legal-commercial center of ancient Israelite urban life: where contracts were witnessed, disputes adjudicated, elders convened (Ruth 4:1; Deut 16:18; Amos 5:10). By positioning himself at the gate, Absalom inserts himself into the judicial space that was David's institutional domain.</p>",
    "3": "<p><em>Ve-hayah kol-ish asher-yihyeh-lo riv la-vo el-ha-melekh la-mishpat va-yiqra elav Avshalom</em> — the formulaic presentation of the petitioner with a legal dispute (<em>riv</em>, lawsuit). Absalom's speech — <em>ein-lekha sho'me'a me'et ha-melekh</em> (there is no one appointed by the king to hear you) — is the political diagnosis that leverages David's judicial inaccessibility. The charge is that the royal judicial system has a structural vacancy that Absalom presents himself as filling.</p>",
    "4": "<p><em>Vayomer Avshalom: mi-yiteneni shofet ba-aretz</em> — the optative (<em>mi-yiteneni</em>) — &ldquo;who will make me...&rdquo; — expresses a wish that is simultaneously a self-nomination. <em>Shofet ba-aretz</em> (judge in the land) invokes the pre-monarchic ideal — the charismatic, accessible leader who judged the people directly. <em>Ve-alai yavo kol-ish asher-yihyeh-lo riv u-mishpat ve-hitzdaqtihu</em> — &ldquo;I will give him justice (<em>hitzdaqtihu</em>, Hiphil of <em>tsadaq</em>, declare righteous/vindicate).&rdquo;</p>",
    "5": "<p><em>Ve-hayah be-qarvato ish le-hishtachavot lo ve-shalach et-yado ve-hecheziq-lo ve-nishaq-lo</em> — the deliberate replacement of prostration-response with an embrace. When a man approached to prostrate before Absalom (<em>hishtachavot</em>), Absalom extended his hand, seized him (<em>hecheziq-lo</em>, Hiphil of <em>chazaq</em>), and kissed him (<em>nashaq</em>). The gesture inverts the royal hierarchy — physically elevating the petitioner rather than receiving honor through his prostration. The combination of grip and kiss makes the manipulation warmly effective.</p>",
    "6": "<p><em>Vayignov Avshalom et-lev anshei Yisra'el</em> — &ldquo;And Absalom stole the hearts (<em>ganav et-lev</em>) of the men of Israel.&rdquo; The verb <em>ganav</em> (steal) for political seduction is a damning editorial verdict. In Gen 31:20, <em>ganav et-lev</em> means deceived. The application here frames the entire four-year campaign as theft: the hearts that properly belong to David were taken by deception. The narrator's choice of <em>ganav</em> signals that the populism was fundamentally dishonest.</p>",
    "7": "<p><em>Va-yehi mi-qetz arba'im shanah</em> — LXX and Syriac read <em>tessara</em> (four) rather than MT's <em>arba'im</em> (forty); most scholars prefer four years as consonant with the narrative timeline. The departure formula — <em>vayomer Avshalom el-ha-melekh: elkhah na ve-ashalem et-nidri</em> (let me go and fulfill my vow) — deploys the irrefusable religious pretext. <em>Neder</em> (vow) was a solemn commitment to YHWH made in a crisis moment, whose fulfillment was a binding religious obligation.</p>",
    "8": "<p><em>Ki neder nadar avdekha be-shivti ve-Geshur ba-Aram lemor: im-yashuv yeshiveni YHWH Yerushalaim ve-avadti et-YHWH</em> — the conditional vow structure: if YHWH returns me to Jerusalem, I will serve YHWH. The condition is already fulfilled; the religious obligation is irrefusable. Absalom's use of <em>avadti et-YHWH</em> (I will serve YHWH) frames the Hebron journey as an act of worship — technically honest, concealing the coup's launch.</p>",
    "9": "<p><em>Vayomer lo ha-melekh: lekh be-shalom</em> — David's blessing: <em>lekh be-shalom</em> (go in peace) is the standard farewell formula of royal dismissal with favor. The irony is terrible: David blesses the conspiracy that will drive him from his throne. <em>Shalom</em> — the word that the house of David will not know until the revolt is over — is the gift David unknowingly bestows on his usurper son.</p>",
    "10": "<p><em>Va-yishlach Avshalom meragelim be-khol shivtei Yisra'el lemor: be-shomakhem et-qol ha-shofar va-amartem: malakh Avshalom be-Chevron</em> — the coordinated announcement. <em>Meragelim</em> (spies/agents) and the <em>qol ha-shofar</em> (voice of the shofar) was the standard signaling instrument for civic proclamation (Num 10:1–10). The simultaneity — across all the tribes at the same moment — was designed to create a political fait accompli before word could reach Jerusalem.</p>",
    "11": "<p><em>Ve-et-Avshalom halekhu matayim ish mi-Yerushalaim qeru'im</em> — two hundred men from Jerusalem going as invited guests. <em>Qeru'im</em> (invited ones, passive participle of <em>qara'</em>). <em>Ve-holkhim be-tumam ve-lo yad'u kol-davar</em> — &ldquo;walking in their innocence (<em>tumam</em>, from <em>tom</em>, integrity) and knowing nothing.&rdquo; <em>Tom</em> (integrity, simplicity) is the vocabulary of moral innocence — these men are victims of Absalom's scheme, not accomplices.</p>",
    "12": "<p><em>Va-yishlach Avshalom et-Achitophel ha-Giloni yo'ets David</em> — the note identifying Ahithophel as &ldquo;David's counselor&rdquo; (<em>yo'ets David</em>) makes his defection's significance explicit. <em>Yo'ets</em> (counselor) was a formal court office. <em>Va-yehi ha-qesher amitz ve-ha-am holekh ve-rav im-Avshalom</em> — the conspiracy grew strong (<em>qesher amitz</em>, a powerful/firm conspiracy) and the people going with Absalom became numerous.</p>",
    "13": "<p><em>Va-yavo ha-maggid el-David lemor: hayah lev-anshei Yisra'el acharei Avshalom</em> — the intelligence report: <em>hayah lev...acharei</em> (the heart was after) echoes the opening of the chapter — the stolen hearts have found their new object.</p>",
    "14": "<p><em>Vayomer David le-khol-avadav: qumu ve-nivrachah ki lo tihyeh-lanu peletah mi-pnei Avshalom</em> — David's flight decision. <em>Nivrachah</em> (let us flee, Qal cohortative of <em>barach</em>) reflects tactical calculation: flight preserves forces for counterattack. <em>Miharu ve-nelkhah</em> (hurry and let us go) — the urgency of <em>maharon</em> (haste) reflects the strategic reality: speed of departure is the difference between escape and capture.</p>",
    "15": "<p><em>Va-yomeru avdei ha-melekh: ke-khol asher-yivchar adoni ha-melekh hinnenu avadekhah</em> — the servants' declaration uses the formula of total conditional loyalty: <em>ke-khol asher-yivchar adoni ha-melekh</em> (whatever my lord the king shall choose). <em>Hinnenu avadekhah</em> (behold, we are your servants) — the deictic <em>hinnenu</em> is the formula of readiness and available obedience.</p>",
    "16": "<p><em>Vayetze ha-melekh ve-khol-beito be-raglav</em> — David going on foot (<em>be-raglav</em>). The king walking rather than riding marks the crisis's severity. <em>Va-ya'azov ha-melekh et eser nashim pilagshim li-shemor ha-bayit</em> — he leaves ten concubines (<em>pilagshim</em>) to keep the house. The ten concubines will become the instruments of Nathan's oracle-fulfillment (16:21–22).</p>",
    "17": "<p><em>Vayetze ha-melekh ve-khol-ha-am be-raglav va-ya'amdu beit ha-merchaq</em> — gathering at <em>beit ha-merchaq</em> (the far house / the last house). <em>Ha-merchaq</em> (distance, remoteness) marks the outermost edge of the city — the last point of urban territory before the wilderness begins. The liminal threshold of the final house before the city ends is the geography of departure.</p>",
    "18": "<p><em>Ve-khol ha-Kerethi ve-khol ha-Pelethi ve-khol ha-Gittim shesh-me'ot ish asher-ba'u me-Gat ovirim al-penei ha-melekh</em> — the three military units: <em>Kerethi</em> and <em>Pelethi</em> (the royal guard corps of possibly Cretan and Philistine origin — cf. 8:18, 20:23); and six hundred Gittites (<em>ha-Gittim</em>) led by Ittai. These were David's personal mercenary forces — professional soldiers bound to him personally, not by Israelite tribal loyalty. <em>Asher-ba'u me-Gat</em> (who came from Gath) explains their immunity to Absalom's Israelite tribal appeal.</p>",
    "19": "<p><em>Vayomer ha-melekh el-Ittai ha-Gitti: lammah telekh gam-atta ittanu</em> — David's offer of release to Ittai. <em>Shub ve-shev im-ha-melekh</em> (return and stay with the king) — here <em>ha-melekh</em> refers to Absalom as the new political reality. <em>Ki nokri attah ve-gam-golah attah li-meqomekha</em> — &ldquo;for you are a foreigner (<em>nokri</em>) and also an exile (<em>golah</em>) from your place.&rdquo; <em>Golah</em> (exile) is a word loaded with pathos — David uses it of Ittai as an honorable acknowledgment of his vulnerable position.</p>",
    "20": "<p><em>Temol bo'akha ve-ha-yom anic'akha lalekheth ittanu ve-ani holekh al-asher-anokhi holekh</em> — &ldquo;you came yesterday, and today I would make you wander up and down with us while I go wherever I go.&rdquo; <em>Nua va-halakha</em> (wander up and down) uses the vocabulary of rootless wandering — the same idiom used for Cain's punishment (Gen 4:12). David honestly represents his situation as exile. The phrase <em>chesed ve-emet</em> (steadfast love and truth) — the paired covenant-loyalty formula of YHWH's own character (Exod 34:6) — is David's blessing on Ittai's departure.</p>",
    "21": "<p><em>Vaya'an Ittai et-ha-melekh vayomar: chai YHWH ve-chai adoni ha-melekh</em> — Ittai's oath formula: <em>chai YHWH</em> (as YHWH lives) combined with <em>chai adoni ha-melekh</em> (as my lord the king lives) is the double divine-royal oath of maximum binding force. <em>Im-be-mavet ve-im-be-chayyim ki im-be-maqom asher yihyeh-sham adoni ha-melekh</em> — &ldquo;whether in death or in life, surely wherever my lord the king shall be, there also will your servant be.&rdquo; The death-life binary mirrors Ruth's oath (Ruth 1:17). A Philistine from Gath swearing by YHWH is one of the Succession Narrative's most theologically striking details.</p>",
    "22": "<p><em>Vayomer David el-Ittai: lekh va-avor</em> — David's grant. <em>Va-ya'avor Ittai ha-Gitti ve-khol-anashav ve-khol-ha-taph asher-itto</em> — the note that Ittai's entire household (<em>taph</em>, small ones, young children) crossed with him emphasizes the totality of his commitment: this is not a soldier's loyalty but a family's choice to follow David into exile.</p>",
    "23": "<p><em>Ve-khol-ha-aretz bokhim be-qol gadol</em> — &ldquo;the whole land was weeping with a loud voice (<em>qol gadol</em>).&rdquo; The communal weeping is a theological register: the land (<em>ha-aretz</em>) — as a quasi-agent — responds to the king's departure. The crossing of the Kidron (<em>Nahal Qidron</em>) — the ravine between Jerusalem and the Mount of Olives — is the physical boundary between the city and the wilderness.</p>",
    "24": "<p><em>Ve-hinneh gam-Tzadoq ve-khol-ha-Leviyyim itto nose'im et-aron berit ha-elohim</em> — the priests carrying the ark of the covenant (<em>aron berit ha-elohim</em>). <em>Vayatssiqu et-aron ha-elohim</em> — the verb <em>yatzeq</em> (to set down, place) marks the careful positioning of the ark. The note about the ark's presence in the fleeing party frames the theological stakes: is the covenant throne-presence abandoning Jerusalem?</p>",
    "25": "<p><em>Vayomer ha-melekh le-Tzadoq: hashev et-aron ha-elohim ha-ir</em> — David's command to return the ark. <em>Im-etmatse chen be-einei YHWH ve-hashivani ve-har'ani oto ve-et-na'vehu</em> — &ldquo;if I find favor in YHWH's eyes, he will bring me back and let me see it and his dwelling place (<em>na'veh</em>).&rdquo; Rather than claiming divine protection through possession of the ark, David acknowledges divine sovereignty over his fate — a theological reversal of the ark-as-guarantee theology that led to disaster in 1 Sam 4.</p>",
    "27": "<p><em>Vayomer ha-melekh el-Tzadoq ha-kohen: ha-ro'eh attah</em> — David addresses Zadok as <em>ha-ro'eh</em> (the seer). The title <em>ro'eh</em> is the archaic term for a prophet (cf. 1 Sam 9:9). The intelligence network: Zadok and Abiathar's sons (<em>Achima'atz ben-Tzadoq ve-Yehonatan ben-Evyatar</em>) as couriers. The specification of both sons by name creates the redundant pathway for the intelligence chain.</p>",
    "28": "<p><em>Re'eh anokhi mitmahmeh be-arvot ha-midbar</em> — David will wait (<em>mitmahmeh</em>, linger) at the fords of the Arabah. <em>Arvot ha-midbar</em> (plains/steppes of the wilderness) designates the Jordan Valley at its lowest point before the fords. <em>Ad bo davar me'imakhem le-haggid li</em> — David will not cross the Jordan until he has intelligence — turning the pause into a tactical listening post.</p>",
    "29": "<p><em>Va-yashev Tzadoq ve-Evyatar et-aron ha-elohim li-Yerushalaim</em> — the ark returns to Jerusalem. The return is irreversible: YHWH's throne-presence stays in the city while its founder-king flees. The theological implication is that YHWH's commitment to Jerusalem is not contingent on David's presence — the city retains its sacred character even during the revolt.</p>",
    "31": "<p><em>Ve-David higgid lemor: Achitophel ba-qosherim im-Avshalom</em> — the intelligence about Ahithophel's defection. David's immediate prayer — <em>YHWH nah-hafar et-atzat Achitophel</em> (O YHWH, please frustrate the counsel of Ahithophel) — uses <em>hafar</em> (frustrate, annul, break) in the Hiphil: a direct petition for divine intervention against a specific threat. The prayer is answered through Hushai in ch. 17 — the narrative explicitly names it as divine causation (17:14).</p>",
    "32": "<p><em>Va-yehi David ba' ad-ha-rosh asher yishtachaveh-sham le-elohim</em> — the summit of the Mount of Olives was a worship site. The appearance of Hushai (<em>re'eh ha-Arki</em>) with coat torn (<em>kutonat qeru'ah</em>) and earth on his head (<em>adama al-rosho</em>) — the mourning posture — is the providential answer to the prayer of v. 31. The physical details of Hushai's mourning dress authenticate his emotional state and make his arrival appear as spontaneous loyalty rather than planned espionage.</p>",
    "33": "<p><em>Vayomer lo David: im-avarta itti ve-hayita alai le-massa</em> — David's assessment: <em>massa'</em> (burden) is the vocabulary of physical and administrative weight. <em>Im-ha-ir tashuv</em> (if you return to the city) reframes Hushai's value: not as a warrior but as an intelligence asset. The phrase <em>le-hatser et-atzat Achitophel</em> (to frustrate the counsel of Ahithophel) explicitly connects Hushai's mission to David's prayer of v. 31.</p>",
    "34": "<p><em>Ve-amarta le-Avshalom: avdekha ha-melekh ehyeh ka-asher hayiti eved avikhah me'az ve-attah gam-ani avedekha</em> — the scripted ambiguous speech. <em>Ka-asher hayiti eved avikhah me'az</em> (as I was your father's servant before) is syntactically ambiguous: it can mean either &ldquo;as I served your father in the past, I serve you now&rdquo; or &ldquo;as I have always served the Davidic king's house, I continue to do so.&rdquo; The ambiguity is the point — each phrase is technically true while meaning something different than Absalom will hear.</p>",
    "35": "<p><em>Ve-lo sham ittekha Tzadoq ve-Evyatar ha-kohanim</em> — the cell structure: Hushai reports to Zadok and Abiathar who relay to their sons (<em>Achima'atz le-Tzadoq ve-Yehonatan le-Evyatar</em>), who carry to David. Three nodes: palace counselor → priests → couriers → king. The three-node structure limits each person's exposure to the full communication chain.</p>",
    "36": "<p><em>Ve-sham itam shney veneihem: Achima'atz le-Tzadoq ve-Yehonatan le-Evyatar</em> — the specification of both sons by name establishes the courier identities for the reader before the dramatic courier race of ch. 18. Ahimaaz will outrun the Cushite (18:19–32); his naming here seeds that narrative tension.</p>",
    "37": "<p><em>Va-yavo Chushai re'eh David ha-ir ve-Avshalom yavo Yerushalaim</em> — the simultaneous arrival formula: Hushai enters the city as Absalom arrives. The <em>re'eh David</em> designation — Hushai as David's official Friend — is his court title, naming his cover role. The simultaneity underscores the providential timing: David's spy is in place before Absalom arrives to need counsel.</p>",
}

CH16 = {
    # v10 already present
    "1": "<p><em>Ve-David avar me'at me-ha-rosh ve-hinneh Tziva na'ar Mephiboshet liqra'to</em> — Ziba's meeting with David at the summit of the Mount of Olives. <em>Me'at me-ha-rosh</em> (a little beyond the summit) places the encounter just after the Mount of Olives worship site. The provisions: two saddled donkeys (<em>chamor sheni chavushim</em>), two hundred loaves of bread (<em>lechem matayim</em>), a hundred clusters of raisins (<em>tzemidei tzimmuqim</em>), a hundred summer fruits (<em>qayitz</em>), and a skin of wine — a complete commissariat provision.</p>",
    "2": "<p><em>Vayomer ha-melekh el-Tziva: mah-elleh lakh</em> — David's inquiry about the purpose of the provisions. Ziba maps each provision to a recipient group: the donkeys for the royal household to ride, the bread and summer fruit for the young men (<em>ne'arim</em>), the wine for the faint (<em>ya'ef ba-midbar</em>, the exhausted in the wilderness). The mapping demonstrates logistical thinking and genuine usefulness — making Ziba's concurrent slander more effective by the contrast of his apparent care.</p>",
    "3": "<p><em>Va-yomer ha-melekh: ve-ayeh ben-adonekha</em> — David's question about Mephibosheth. Ziba's accusation: <em>yashav bi-Yerushalaim ki amar: ha-yom yashivu li beit Yisra'el et-mamlekhut avi</em> — &ldquo;he remains in Jerusalem, for he said, Today the house of Israel will restore to me the kingdom of my father.&rdquo; <em>Yashivu li</em> (they will restore to me) uses the Hiphil of <em>shuv</em> — the politically charged vocabulary of restoration. Whether Mephibosheth said this (cf. 19:24–30) cannot be determined; Ziba's unverified report is the only evidence David hears before judging.</p>",
    "4": "<p><em>Vayomer ha-melekh le-Tziva: hinneh lekha kol asher li-Mephiboshet</em> — David's immediate judgment: everything that belongs to Mephibosheth is Ziba's. <em>Hinneh lekha</em> (behold, to you) is a royal grant formula — immediate and categorical. The decision made under duress without hearing Mephibosheth will haunt David; in 19:29 he splits the property — a compromise that implicitly acknowledges the rashness of the original judgment.</p>",
    "5": "<p><em>U-va David ad-Bachurim ve-hinneh mi-sham yotze ish mi-mishpachat beit-Sha'ul u-shemo Shim'i ben-Gera yotze yatzo u-meqallel</em> — Shimei (<em>Shim'i ben-Gera</em>) coming out cursing (<em>meqallel</em>, Piel participle of <em>qalal</em>, to curse, diminish). The Piel of <em>qalal</em> was the formal vocabulary of cursing — calling down diminishment and contempt on the target. <em>Mi-mishpachat beit-Sha'ul</em> identifies the tribal and dynastic motive: Benjaminite loyalty to the Saulide house.</p>",
    "6": "<p><em>Va-yeqallel va-yishlakh avanim el-David ve-el kol-avdei ha-melekh David</em> — throwing stones (<em>shalakh avanim</em>) at David and all his servants. Stone-throwing was a calculated insult and physical assault. <em>Ve-khol-ha-am ve-khol-ha-gibborim mi-ymino u-mi-smolo</em> — all the people and all the mighty men (<em>gibborim</em>) flanking David — the elite warriors who could have killed Shimei instantly, yet David commands restraint. The power asymmetry is deliberate.</p>",
    "7": "<p><em>Ve-kho amar Shim'i be-qaleloh: tze tze ish ha-damim ve-ish ha-beliya'al</em> — <em>tze tze</em> is the intensive expulsion formula — a doubled imperative of <em>yatza</em> (go out). <em>Ish ha-damim</em> (man of blood/bloodshed) — the construct phrase of bloodguilt. <em>Ish ha-beliya'al</em> (man of worthlessness, <em>beliya'al</em> = without value/profit) — the strongest social condemnation combining criminal charge with moral nullity.</p>",
    "8": "<p><em>Heshiv alekha YHWH kol-damei beit Sha'ul asher malakhta tachtav</em> — Shimei's theological indictment: YHWH has returned (<em>heshiv</em>, Hiphil of <em>shuv</em>) upon David all the blood of Saul's house for which David ruled in his place. <em>Va-yitten YHWH et-ha-mamlakhah be-yad Avshalom binekha</em> — YHWH has given the kingdom into Absalom's hand. Shimei's theology of direct divine retribution — the coup as YHWH's punishment for David's bloodguilt — is not endorsed by the narrator but is also not directly refuted by David.</p>",
    "9": "<p><em>Vayomer Avishai ben-Tzeruyah el-ha-melekh: lammah yeqallel ha-kelev ha-met ha-zeh et-adoni ha-melekh</em> — Abishai's characterization of Shimei as <em>ha-kelev ha-met ha-zeh</em> (this dead dog). <em>Kelev met</em> (dead dog) is the lowest social category in Hebrew social vocabulary — combining the uncleanness of the dog with the powerlessness of death. The term appears in 1 Sam 24:15 (David's self-deprecation) and 9:8 (Mephibosheth's self-deprecation) — here deployed as the maximum insult for Shimei.</p>",
    "11": "<p><em>Vayomer David el-Avishai ve-el kol-avadav: hinneh beni asher yatza mi-me'ai mevasheq et-naphshi</em> — David's argument for restraint: if his own son (who came from his own bowels, <em>yatza mi-me'ai</em>, the most intimate biological connection) seeks his life (<em>mevasheq et-naphshi</em>), how much more this Benjaminite! The <em>qal va-chomer</em> (lesser to greater) argument: if the most intimate person wants him dead, the distant enemy's curse is small by comparison.</p>",
    "12": "<p><em>Ulai yir'eh YHWH be-onyi ve-heshhiv YHWH li tovah tachat qillato ha-yom</em> — David's hope: <em>yir'eh YHWH be-onyi</em> (YHWH will look upon my affliction/<em>oni</em>). The noun <em>oni</em> (affliction, humiliation) is the vocabulary of the oppressed petitioner — it appears in Hannah's prayer (1 Sam 1:11) and the exodus narrative (Exod 3:7). <em>Ve-heshhiv YHWH li tovah tachat qillato ha-yom</em> — the hope that YHWH will return good for today's curse is the theology of redemptive inversion: curse becoming blessing through divine mediation.</p>",
    "13": "<p><em>Va-yelekh David ve-anashav ba-derekh ve-Shim'i holekh al-tzela ha-har le-negdo</em> — the visual geometry of the parallel march: David on the road, Shimei on the hillside (<em>tzela ha-har</em>, the slope/side of the mountain) moving parallel alongside, cursing and throwing stones and dust (<em>ve-ipper be-aphar</em>). The <em>ipper be-aphar</em> (hurling dust) is an escalating form of contemptuous assault that accompanied stone-throwing.</p>",
    "14": "<p><em>Va-yavo ha-melekh ve-khol-ha-am asher itto ayephim</em> — <em>ayephim</em> (exhausted, weary) from the adjective <em>ayef</em>. The arrival at the Jordan after approximately 30 km of difficult terrain — with women, children, and the entire household — explains the urgency of rest. This exhaustion is precisely the tactical vulnerability that Ahithophel's advice in ch. 17 correctly identifies: strike now, before David can regroup.</p>",
    "15": "<p><em>Ve-Avshalom ve-khol-ha-am anshei Yisra'el ba'u Yerushalaim ve-Achitophel itto</em> — the arrival of Absalom in Jerusalem with all Israel's men and Ahithophel with him. The weighted final note — <em>Achitophel itto</em> (Ahithophel was with him) — signals the political danger. Ahithophel's presence transforms Absalom's successful coup into a strategically guided threat against David.</p>",
    "16": "<p><em>Va-yehi ka-asher-ba Chushai ha-Arki re'eh David el-Avshalom vayomer Chushai le-Avshalom: yechi ha-melekh yechi ha-melekh</em> — <em>yechi ha-melekh</em> (long live the king) — the standard royal acclamation. The double repetition (<em>yechi yechi</em>) is hyperbolic enthusiasm. The narrator's retention of the title <em>re'eh David</em> (David's Friend) even as Hushai addresses Absalom is a winking signal to the reader: this is still David's Friend performing the role of Absalom's advisor.</p>",
    "17": "<p><em>Vayomer Avshalom el-Chushai: zeh chasedkhah et-re'ekha</em> — Absalom's challenge: <em>chasedkhah</em> (your loyalty, <em>chesed</em>) to your friend. The use of <em>chesed</em> — the covenant-loyalty term — frames Hushai's presence as a violation of the primary loyalty relationship. Absalom is testing whether the friendship with David is genuine or negotiable.</p>",
    "18": "<p><em>Vayomer Chushai el-Avshalom: lo ki asher bachar YHWH ve-ha-am ha-zeh ve-khol ish Yisra'el lo ehyeh ve-itto eshev</em> — Hushai's answer deploys the election vocabulary: <em>bachar YHWH</em> (whom YHWH has chosen). The argument is that YHWH's choice is expressed through the people's choice — and the people have chosen Absalom. The statement is technically true as a statement of political theology while being personally dishonest: Hushai does not believe YHWH has chosen Absalom.</p>",
    "19": "<p><em>Ve-ha-shenit li-mi ani evod ha-lo lifnei vno</em> — &ldquo;and secondly, whom should I serve? Should it not be before his son?&rdquo; The dynastic-continuity argument: service to the Davidic line rather than to an individual king. <em>Ka-asher avadti lifnei avikhah ken ehyeh lefanekhah</em> — &ldquo;as I served before your father, so I will serve before you.&rdquo; The ambiguity is maintained: technically describing service to the Davidic line, which continues to be true.</p>",
    "20": "<p><em>Vayomer Avshalom el-Achitophel: havu lakhem etza mah na'aseh</em> — Absalom's formal consultation of Ahithophel: <em>havu lakhem etza</em> (give counsel to us). The plural <em>lakhem</em> (to us) includes the assembled elders. <em>Mah na'aseh</em> (what shall we do) is the decision-making formula that activates the counselor's authoritative role. Ahithophel's response will be the most politically acute counsel in the narrative — and the one YHWH will overturn through Hushai.</p>",
    "21": "<p><em>Vayomer Achitophel el-Avshalom: bo el-pilagshei avikhah asher hinnich lishemor ha-bayit</em> — Ahithophel's advice: go to your father's concubines (<em>pilagshei avikhah</em>). <em>Ve-shama kol-Yisra'el ki-niv'ashta et-avikhah</em> — &ldquo;and all Israel will hear that you have made yourself abhorrent (<em>niv'ashta</em>, Niphal of <em>ba'ash</em>, stink, be loathsome) to your father.&rdquo; The political logic: an irreversible action forces full commitment from all followers — no one can hedge by hoping for father-son reconciliation. <em>Ve-chazqu yadei kol-asher ittakh</em> — the hands of all with you will be strengthened.</p>",
    "22": "<p><em>Va-yattu le-Avshalom ha-ohel al-ha-gag</em> — the tent (<em>ohel</em>) erected on the rooftop (<em>ha-gag</em>) — the same roof from which David saw Bathsheba (11:2). <em>Va-yavo Avshalom el-pilagshei aviv le-einei kol-Yisra'el</em> — Absalom went to his father's concubines in the sight of all Israel. Nathan's oracle (12:11–12) spoke of precisely this public humiliation: <em>ve-natalti et-nashekha le-einekha... ve-shakhav im-nashekha le-einei ha-shemesh ha-zeh</em> (I will take your wives before your eyes... in the sight of this sun). The verbal echo between oracle and fulfillment is exact.</p>",
    "23": "<p><em>Va-atzat Achitophel asher ya'ats ba-yamim ha-hem ke-asher yish'al bi-devar ha-elohim</em> — the narrative assessment of Ahithophel's counsel: in those days his advice was &ldquo;as though one consulted the word of God.&rdquo; <em>Ke-asher yish'al bi-devar ha-elohim</em> (as when one inquired of the word of God) — this is the narrator's sociological observation, not theological endorsement: both Absalom's court and David's camp treated his advice as determinative. This exalted reputation is precisely what makes Hushai's counter-counsel so remarkable — and makes its success so explicitly attributed to divine intervention (17:14).</p>",
}

